// ❌ BAD: UserService handles both user logic AND email sending
class UserService {
    void register(User user) { db.save(user); sendWelcomeEmail(user); }
    void sendWelcomeEmail(User user) { /* email logic */ }
}

// ✅ GOOD: separate responsibilities
class UserService    { void register(User u) { db.save(u); emailService.sendWelcome(u); } }
class EmailService   { void sendWelcome(User u) { /* email logic */ } }

// ❌ BAD: add new shape = edit existing class
class AreaCalc { double area(Object shape) { if (shape instanceof Circle) ... else if ... } }

// ✅ GOOD: new shape = new class
interface Shape { double area(); }
class Circle implements Shape { double area() { return Math.PI * r * r; } }
class Square implements Shape { double area() { return side * side; } }

// ❌ VIOLATION: Square breaks Rectangle contract
class Rectangle { setWidth(w); setHeight(h); }
class Square extends Rectangle {
    void setWidth(int w) { this.w = this.h = w; } // breaks callers expecting independent dimensions
}

// ✅ FIX: don't extend if behaviour differs
interface Shape { double area(); }
class Rectangle implements Shape { ... }
class Square    implements Shape { ... }

// ❌ BAD: printer forced to implement fax
interface Machine { print(); scan(); fax(); }
class OldPrinter implements Machine { fax() { throw new UnsupportedOperationException(); } }

// ✅ GOOD: segregated
interface Printer { print(); }
interface Scanner { scan(); }
class OldPrinter implements Printer { print() { ... } }

// ❌ BAD: high-level depends on concrete low-level
class OrderService { private MySQLRepo repo = new MySQLRepo(); }

// ✅ GOOD: depend on abstraction, inject implementation
class OrderService {
    private final OrderRepository repo; // interface
    OrderService(OrderRepository repo) { this.repo = repo; } // injected
}
// Spring does this automatically with @Autowired / constructor injection
